SET client_encoding TO 'UTF8';

SET check_function_bodies = false;

DROP TRIGGER IF EXISTS tbiu_sc_fin_money_return ON sc_fin_money_return CASCADE;
CREATE OR REPLACE FUNCTION trigger_fct_tbiu_sc_fin_money_return() RETURNS trigger AS $BODY$
BEGIN

    if coalesce(NEW.item_no::text, '') = '' or NEW.item_no = 0 then
        select max(item_no) into STRICT NEW.item_no
        from sc_fin_money_return
        where membership_no = NEW.membership_no;
        NEW.item_no := coalesce(NEW.item_no,0) + 1;
    end if;

    if coalesce(NEW.cancel_status::text, '') = '' then NEW.cancel_status :='0';end if;
    if coalesce(NEW.manual_status::text, '') = '' then NEW.manual_status :='0';end if;
    if coalesce(NEW.return_status::text, '') = '' then NEW.return_status :='0';end if;
    if coalesce(NEW.mrt_able::text, '') = '' then NEW.mrt_able :='0';end if;
    --Niorn 2024-02-22 Trans_status เป็นได้แค่ 0 กับ 1 
    --if :new.tran_status is null then :new.tran_status :='0';end if;
    if coalesce(NEW.tran_status::text, '') = '' or NEW.tran_status = '2' then NEW.tran_status :='0';end if;

--     --KTM เงินทดรองดำเนินคดี ตั้งแล้วจ่ายเลย
--    if :new.return_method = '125' or :new.return_method = '126' or :new.return_method = '127' then
--      :new.return_status := '1' ;
--    end if ;
    if coalesce(NEW.request_status::text, '') = ''  then NEW.request_status :='0';end if;
      
    --KTM ถ้าคืนจากใบเสร็จ ให้ลดยอดต่อได้    
    if NEW.return_method = 'KEP' then
      NEW.mrt_able := '1';
    else
       --KTM เซตเตรียมจ่ายเป็นเงินสดเลย
      if coalesce(NEW.request_method::text, '') = '' then NEW.request_method :='CSH';end if;
    end if;


    if NEW.request_status ='1' and coalesce(NEW.paid_date::text, '') = ''  then
      NEW.paid_date :=  pka_fin_daily.fp_finance_date('1');
    end if;

    --Niorn 2023-09-29 TGE ถ้ามีการเตรียมให้ระบุวันที่เตรียมด้วย ( ถ้าไม่มี ) ใช้ออกรายงานเตรียมจ่าย
    if NEW.request_status ='1' and coalesce(NEW.request_date::text, '') = ''  then
      NEW.request_date :=  pka_fin_daily.fp_finance_date('1');
      NEW.request_id :=  current_setting('app.login_id', true);
    end if;

     --Niorn 2023-09-29 TGE ถ้ามีการเตรียมไว้แล้ว แล้วมาเตรียมใหม่ ให้บันทึกวันที่เตรียมใหม่
    if NEW.request_status ='1' and (   NEW.request_method <> OLD.request_method 
            or   NEW.request_bankid <> OLD.request_bankid 
            or   NEW.request_bankac <> OLD.request_bankac  ) then

      NEW.request_date := pka_fin_daily.fp_finance_date('1');
      NEW.request_id :=  current_setting('app.login_id', true);
    end if;

    --Niorn 2023-04-30 TGE
    if NEW.request_status ='0'  then
      NEW.paid_date :=  null;
      --:new.request_id := null ;
      --:new.request_date := null ; 
    end if;


 if (  (OLD.membership_no IS NOT NULL AND OLD.membership_no::text <> '')  
        and  NEW.membership_no <> OLD.membership_no )  then 
    update sc_fin_money_return_det
    set membership_no = NEW.membership_no
    where membership_no = OLD.membership_no
    and item_no = OLD.item_no;

 end if;

  if coalesce(NEW.owner_name::text, '') = '' then 
    NEW.owner_name := pka_com_function.fp_get_member_name( NEW.membership_no );
  end if;

--Niorn 2023-05-05 TGE เพิ่มเก็บ entry_id , entry_date   
if coalesce(NEW.entry_id::text, '') = '' then NEW.entry_id :=  current_setting('app.login_id', true);end if;
if coalesce(NEW.entry_date::text, '') = '' then NEW.entry_date :=  statement_timestamp();end if;

--Niorn 2024-06-30 POT ยอดเป็น 0 ปรับสถานะเป็นยกเลิกไปเลย
if NEW.money_return = 0 then NEW.cancel_status := '1';end if;

--Niorn 2024-07-04 MWA ปรับสถานะเป็นรอโอน ถ้า สถานะเตรียมจ่าย เป็นรอจ่าย
if NEW.request_status = 0 then NEW.tran_status := '0';end if;

RETURN NEW;
end
$BODY$
 LANGUAGE 'plpgsql' SECURITY DEFINER;
-- REVOKE ALL ON FUNCTION trigger_fct_tbiu_sc_fin_money_return() FROM PUBLIC;

CREATE TRIGGER tbiu_sc_fin_money_return
	BEFORE INSERT OR UPDATE ON sc_fin_money_return FOR EACH ROW
	EXECUTE PROCEDURE trigger_fct_tbiu_sc_fin_money_return();

